154	    @Override
155	    public PageResult<SecurityPatrolPageBO> securityPatrolPage(SecurityPatrolQueryBO queryBO) {
156	        Page<HseSecurityPatrol> page = new Page<>(queryBO.getPageNum(), queryBO.getPageSize());
157	        LambdaQueryWrapper<HseSecurityPatrol> queryWrapper = new LambdaQueryWrapper<>();
158	
159	        if (queryBO.getStatus() != null) {
160	            queryWrapper.eq(HseSecurityPatrol::getStatus, queryBO.getStatus());
161	        }
162	
163	        if (queryBO.getStartDate() != null && queryBO.getEndDate() != null) {
164	            queryWrapper.between(HseSecurityPatrol::getPatrolDate, queryBO.getStartDate(), queryBO.getEndDate());
165	        }
166	        queryWrapper.orderByDesc(HseSecurityPatrol::getSubmitTime);
167	
168	        IPage<HseSecurityPatrol> pageResult = this.page(page, queryWrapper);
169	
170	        if (CollectionUtils.isEmpty(pageResult.getRecords())) {
171	            return PageResult.empty();
172	        }
173	        List<Long> securityPatrolIds = pageResult.getRecords().stream()
174	                .map(HseSecurityPatrol::getSecurityPatrolId)
175	                .collect(Collectors.toList());
176	
177	        LambdaQueryWrapper<HseSecurityPatrolAnswer> answerQueryWrapper = new LambdaQueryWrapper<>();
178	        answerQueryWrapper.in(HseSecurityPatrolAnswer::getSecurityPatrolId, securityPatrolIds);
179	        List<HseSecurityPatrolAnswer> answerList = hseSecurityPatrolAnswerService.list(answerQueryWrapper);
180	
181	        Map<Long, Long> answerCountMap = answerList.stream()
182	                .collect(Collectors.groupingBy(HseSecurityPatrolAnswer::getSecurityPatrolId, Collectors.counting()));
183	
184	
185	//        List<Long> patrollerUserIds = pageResult.getRecords().stream()
186	//                .map(HseSecurityPatrol::getPatrollerUserId)
187	//                .filter(id -> id != null)
188	//                .distinct()
189	//                .collect(Collectors.toList());
190	
191	//        Map<Long, UserEntity> userMap = CollectionUtils.isEmpty(patrollerUserIds)
192	//                ? new java.util.HashMap<>()
193	//                : userService.getUserMapByUserId(patrollerUserIds);
194	
195	        List<SecurityPatrolPageBO> boList = new ArrayList<>();
196	        for (HseSecurityPatrol entity : pageResult.getRecords()) {
197	            SecurityPatrolPageBO bo = new SecurityPatrolPageBO();
198	            bo.setSecurityPatrolId(entity.getSecurityPatrolId());
199	            bo.setPatrolDate(entity.getPatrolDate());
200	            bo.setShift(entity.getShift());
201	            bo.setStatus(entity.getStatus());
202	            bo.setAnswerCount(answerCountMap.getOrDefault(entity.getSecurityPatrolId(), 0L).intValue());
203	            bo.setPatrollerUser(entity.getPatrollerUser());
204	
205	            boList.add(bo);
206	        }
207	
208	        return new PageResult<>(boList, pageResult.getTotal());
209	    }
