211	    @Override
212	    public Long securityPatrolSave(SecurityPatrolSaveBO saveBO) {
213	
214	        long id = IdWorker.getId();
215	        HseSecurityPatrol hseSecurityPatrol = new HseSecurityPatrol();
216	        hseSecurityPatrol.setPatrolDate(saveBO.getPatrolDate());
217	        hseSecurityPatrol.setSecurityPatrolId(id);
218	        hseSecurityPatrol.setShift(saveBO.getShift());
219	        hseSecurityPatrol.setPatrollerUser(saveBO.getPatrollerUser());
220	        hseSecurityPatrol.setStatus(SecurityPatrolStatusEnum.DRAFT.getCode());
221	        Long userId = UserContextHolder.getUserId();
222	        hseSecurityPatrol.setContractorId(userId);
223	        List<HseSecurityPatrolFormCategory> patrolFormCategoryList = hseSecurityPatrolFormCategoryService.list();
224	
225	        List<Long> categoryIds = patrolFormCategoryList.stream()
226	            .map(HseSecurityPatrolFormCategory::getCategoryId)
227	            .collect(Collectors.toList());
228	
229	        LambdaQueryWrapper<HseSecurityPatrolChecklistItem> hseSecurityPatrolChecklistItemLambdaQueryWrapper =
230	            new LambdaQueryWrapper<>();
231	        hseSecurityPatrolChecklistItemLambdaQueryWrapper.in(HseSecurityPatrolChecklistItem::getCategoryId, categoryIds);
232	        List<HseSecurityPatrolChecklistItem> patrolChecklistItemList =
233	            hseSecurityPatrolChecklistItemService.list(hseSecurityPatrolChecklistItemLambdaQueryWrapper);
234	        Map<Long, List<HseSecurityPatrolChecklistItem>> patrolChecklistItemMap = patrolChecklistItemList.stream()
235	                .collect(Collectors.groupingBy(HseSecurityPatrolChecklistItem::getCategoryId));
236	
237	        List<HseSecurityPatrolAnswer> hseSecurityPatrolAnswers = new ArrayList<>();
238	        for (HseSecurityPatrolFormCategory hseSecurityPatrolFormCategory : patrolFormCategoryList) {
239	            List<HseSecurityPatrolChecklistItem> hseSecurityPatrolChecklistItems = patrolChecklistItemMap.get(hseSecurityPatrolFormCategory.getCategoryId());
240	            if (hseSecurityPatrolFormCategory.getType() == SecurityPatrolFormCategoryTypeEnum.INSIDE_THE_BUILDING
241	                .getCode()
242	                || hseSecurityPatrolFormCategory.getType() == SecurityPatrolFormCategoryTypeEnum.PARKING.getCode()) {
243	                if (CollectionUtils.isNotEmpty(hseSecurityPatrolChecklistItems)){
244	                    for (HseSecurityPatrolChecklistItem hseSecurityPatrolChecklistItem : hseSecurityPatrolChecklistItems) {
245	                        for (String floorCode : FLOOR_CODE_LIST) {
246	                            HseSecurityPatrolAnswer hseSecurityPatrolAnswer = new HseSecurityPatrolAnswer();
247	                            hseSecurityPatrolAnswer.setPatrolAnswerId(IdWorker.getId());
248	                            hseSecurityPatrolAnswer.setSecurityPatrolId(id);
249	                            hseSecurityPatrolAnswer.setType(hseSecurityPatrolFormCategory.getType());
250	                            hseSecurityPatrolAnswer.setFormCategoryId(hseSecurityPatrolFormCategory.getCategoryId());
251	                            hseSecurityPatrolAnswer.setFormCategoryName(hseSecurityPatrolFormCategory.getName());
252	                            hseSecurityPatrolAnswer.setFormCategoryNameAr(hseSecurityPatrolFormCategory.getNameAr());
253	                            hseSecurityPatrolAnswer.setFloorCode(floorCode);
254	                            hseSecurityPatrolAnswer.setChecklistItemId(hseSecurityPatrolChecklistItem.getChecklistItemId());
255	                            hseSecurityPatrolAnswer.setChecklistItemName(hseSecurityPatrolChecklistItem.getName());
256	                            hseSecurityPatrolAnswer.setChecklistItemNameAr(hseSecurityPatrolChecklistItem.getNameAr());
257	                            hseSecurityPatrolAnswer.setIsSituation(IsSituationEnum.YES.getCode());
258	                            hseSecurityPatrolAnswer.setOrgId(hseSecurityPatrolChecklistItem.getOrgId());
259	                            hseSecurityPatrolAnswers.add(hseSecurityPatrolAnswer);
260	                        }
261	                    }
262	                }
263	            }else {
264	                for (HseSecurityPatrolChecklistItem hseSecurityPatrolChecklistItem : hseSecurityPatrolChecklistItems) {
265	                    HseSecurityPatrolAnswer hseSecurityPatrolAnswer = new HseSecurityPatrolAnswer();
266	                    hseSecurityPatrolAnswer.setPatrolAnswerId(IdWorker.getId());
267	                    hseSecurityPatrolAnswer.setSecurityPatrolId(id);
268	                    hseSecurityPatrolAnswer.setType(hseSecurityPatrolFormCategory.getType());
269	                    hseSecurityPatrolAnswer.setFormCategoryId(hseSecurityPatrolFormCategory.getCategoryId());
270	                    hseSecurityPatrolAnswer.setFormCategoryName(hseSecurityPatrolFormCategory.getName());
271	                    hseSecurityPatrolAnswer.setFormCategoryNameAr(hseSecurityPatrolFormCategory.getNameAr());
272	                    hseSecurityPatrolAnswer.setChecklistItemId(hseSecurityPatrolChecklistItem.getChecklistItemId());
273	                    hseSecurityPatrolAnswer.setChecklistItemName(hseSecurityPatrolChecklistItem.getName());
274	                    hseSecurityPatrolAnswer.setChecklistItemNameAr(hseSecurityPatrolChecklistItem.getNameAr());
275	                    hseSecurityPatrolAnswer.setIsSituation(IsSituationEnum.YES.getCode());
276	                    hseSecurityPatrolAnswer.setOrgId(hseSecurityPatrolChecklistItem.getOrgId());
277	                    hseSecurityPatrolAnswers.add(hseSecurityPatrolAnswer);
278	                }
279	            }
280	        }
281	        if (CollectionUtils.isNotEmpty(hseSecurityPatrolAnswers)){
282	            hseSecurityPatrolAnswerService.saveBatch(hseSecurityPatrolAnswers);
283	        }
284	        save(hseSecurityPatrol);
285	        return hseSecurityPatrol.getSecurityPatrolId();
286	    }
