288	    @Override
289	    public SecurityPatrolDetailBO securityPatrolDetail(Long securityPatrolId) {
290	        if (securityPatrolId == null){
291	            throw new BusinessException(CommonError.PARAM_ERROR.getCode());
292	        }
293	        LambdaQueryWrapper<HseSecurityPatrol> hseSecurityPatrolLambdaQueryWrapper = new LambdaQueryWrapper<>();
294	        hseSecurityPatrolLambdaQueryWrapper.eq(HseSecurityPatrol::getSecurityPatrolId,securityPatrolId);
295	        HseSecurityPatrol hseSecurityPatrol = getOne(hseSecurityPatrolLambdaQueryWrapper);
296	        if (hseSecurityPatrol == null){
297	            throw new BusinessException(CommonError.PARAM_ERROR.getCode());
298	        }
299	
300	        SecurityPatrolDetailBO securityPatrolDetailBO = new SecurityPatrolDetailBO();
301	        securityPatrolDetailBO.setSecurityPatrolId(hseSecurityPatrol.getSecurityPatrolId());
302	        securityPatrolDetailBO.setPatrollerUser(hseSecurityPatrol.getPatrollerUser());
303	        securityPatrolDetailBO.setPatrolDate(hseSecurityPatrol.getPatrolDate());
304	        securityPatrolDetailBO.setShift(hseSecurityPatrol.getShift());
305	        securityPatrolDetailBO.setStatus(hseSecurityPatrol.getStatus());
306	
307	        LambdaQueryWrapper<ContractorEmployeeEntity> hseCorrectiveActionsEntityLambdaQueryWrapper = new LambdaQueryWrapper<>();
308	        hseCorrectiveActionsEntityLambdaQueryWrapper.eq(ContractorEmployeeEntity::getContractorEmployee,hseSecurityPatrol.getContractorId());
309	        ContractorEmployeeEntity contractorEmployee = contractorEmployeeService.getOne(hseCorrectiveActionsEntityLambdaQueryWrapper);
310	        if (contractorEmployee != null){
311	            securityPatrolDetailBO.setContractorId(contractorEmployee.getContractorEmployee());
312	            securityPatrolDetailBO.setContractorName(contractorEmployee.getName());
313	        }
314	
315	
316	
317	
318	        LambdaQueryWrapper<HseSecurityPatrolAnswer> hseSecurityPatrolAnswerEntityLambdaQueryWrapper =
319	                new LambdaQueryWrapper<>();
320	        hseSecurityPatrolAnswerEntityLambdaQueryWrapper.eq(HseSecurityPatrolAnswer::getSecurityPatrolId,
321	                securityPatrolId);
322	        List<HseSecurityPatrolAnswer> hseInspectionAnswerEntityList =
323	                hseSecurityPatrolAnswerService.list(hseSecurityPatrolAnswerEntityLambdaQueryWrapper);
324	        if (hseInspectionAnswerEntityList.isEmpty()) {
325	            return securityPatrolDetailBO;
326	        }
327	
328	        List<Long> formCategoryIds = hseInspectionAnswerEntityList.stream().map(HseSecurityPatrolAnswer::getFormCategoryId).collect(Collectors.toList());
329	
330	        LambdaQueryWrapper<HseSecurityPatrolFormCategory> hseSecurityPatrolFormCategoryLambdaQueryWrapper =
331	            new LambdaQueryWrapper<>();
332	        hseSecurityPatrolFormCategoryLambdaQueryWrapper.in(HseSecurityPatrolFormCategory::getCategoryId,
333	            formCategoryIds);
334	        List<HseSecurityPatrolFormCategory> securityPatrolFormCategoryList =
335	            hseSecurityPatrolFormCategoryService.list(hseSecurityPatrolFormCategoryLambdaQueryWrapper);
336	        Map<Long,
337	            HseSecurityPatrolFormCategory> securityPatrolFormCategoryMap = securityPatrolFormCategoryList.stream().collect(Collectors.toMap(HseSecurityPatrolFormCategory::getCategoryId, Function.identity()));
338	
339	
340	        List<Long> orgIds = hseInspectionAnswerEntityList.stream().map(HseSecurityPatrolAnswer::getOrgId).collect(Collectors.toList());
341	
342	        LambdaQueryWrapper<OrganizationEntity> organizationEntityLambdaQueryWrapper = new LambdaQueryWrapper<>();
343	        organizationEntityLambdaQueryWrapper.in(OrganizationEntity::getOrgId,orgIds);
344	        List<OrganizationEntity> orgList = organizationService.list(organizationEntityLambdaQueryWrapper);
345	
346	        Map<Long, OrganizationEntity> orgMap = orgList.stream().collect(Collectors.toMap(OrganizationEntity::getOrgId, Function.identity()));
347	        List<PatrolAnswerBO> patrolAnswerBOS = new ArrayList<>();
348	        for (HseSecurityPatrolAnswer hseSecurityPatrolAnswerEntity : hseInspectionAnswerEntityList) {
349	            PatrolAnswerBO patrolAnswerBO = new PatrolAnswerBO();
350	            patrolAnswerBO.setSecurityPatrolId(hseSecurityPatrolAnswerEntity.getSecurityPatrolId());
351	            patrolAnswerBO.setPatrolAnswerId(hseSecurityPatrolAnswerEntity.getPatrolAnswerId());
352	            patrolAnswerBO.setFormCategoryId(hseSecurityPatrolAnswerEntity.getFormCategoryId());
353	            patrolAnswerBO.setChecklistItemId(hseSecurityPatrolAnswerEntity.getChecklistItemId());
354	            patrolAnswerBO.setFloorCode(hseSecurityPatrolAnswerEntity.getFloorCode());
355	            Integer isSituation = resolveDisplayIsSituation(hseSecurityPatrolAnswerEntity.getIsSituation());
356	            patrolAnswerBO.setIsSituation(isSituation);
