748	    private void applySaveFromYesNoBranch(HseSecurityPatrolAnswer hseSecurityPatrolAnswer,
749	                                          AnswerSaveBO answerSaveBO) {
750	        Integer isSituation = resolveSaveIsSituation(answerSaveBO.getIsSituation());
751	        answerSaveBO.setIsSituation(isSituation);
752	        hseSecurityPatrolAnswer.setIsSituation(isSituation);
753	        hseSecurityPatrolAnswerService.updateById(hseSecurityPatrolAnswer);
754	        if (IsSituationEnum.YES.getCode().equals(isSituation)) {
755	            LambdaQueryWrapper<HsePatrolCorrectiveAction> deleteQuery = new LambdaQueryWrapper<>();
756	            deleteQuery.eq(HsePatrolCorrectiveAction::getPatrolAnswerId, answerSaveBO.getPatrolAnswerId());
757	            hsePatrolCorrectiveActionService.remove(deleteQuery);
758	            return;
759	        }
760	
761	        if (IsSituationEnum.NO.getCode().equals(isSituation)) {
762	            LambdaQueryWrapper<HsePatrolCorrectiveAction> oldQuery = new LambdaQueryWrapper<>();
763	            oldQuery.eq(HsePatrolCorrectiveAction::getPatrolAnswerId, answerSaveBO.getPatrolAnswerId());
764	            List<HsePatrolCorrectiveAction> oldList = hsePatrolCorrectiveActionService.list(oldQuery);
765	
766	            Map<Long, HsePatrolCorrectiveAction> oldMap = oldList.stream()
767	                    .filter(ca -> ca.getCorrectiveActionsId() != null)
768	                    .collect(Collectors.toMap(HsePatrolCorrectiveAction::getCorrectiveActionsId, Function.identity()));
769	
770	            Set<Long> newIds = new HashSet<>();
771	            if (CollectionUtils.isNotEmpty(answerSaveBO.getFindings())) {
772	                for (patrolIdFindingSaveBO finding : answerSaveBO.getFindings()) {
773	                    if (finding.getCorrectiveActionsId() != null && oldMap.containsKey(finding.getCorrectiveActionsId())) {
774	                        HsePatrolCorrectiveAction oldEntity = oldMap.get(finding.getCorrectiveActionsId());
775	                        oldEntity.setNotes(finding.getFindingRemarks());
776	                        oldEntity.setCorrectiveAction(finding.getCorrectiveAction());
777	                        oldEntity.setOrgId(finding.getOrgId());
778	                        oldEntity.setSecurityPatrolId(hseSecurityPatrolAnswer.getSecurityPatrolId());
779	                        oldEntity.setTargetClosureDate(finding.getTargetClosureDate());
780	                        hsePatrolCorrectiveActionService.updateById(oldEntity);
781	
782	                        if (CollectionUtils.isNotEmpty(finding.getAttachmentList())) {
783	                            processAttachment(oldEntity.getCorrectiveActionsId(),
784	                                    finding.getAttachmentList(), AttachTypeEnum.CORRECTIVE_ACTION);
785	                        }
786	                        newIds.add(finding.getCorrectiveActionsId());
787	                    } else {
788	                        HsePatrolCorrectiveAction newEntity = new HsePatrolCorrectiveAction();
789	                        newEntity.setCorrectiveActionsId(IdWorker.getId());
790	                        newEntity.setPatrolAnswerId(hseSecurityPatrolAnswer.getPatrolAnswerId());
791	                        newEntity.setNotes(finding.getFindingRemarks());
792	                        newEntity.setCorrectiveAction(finding.getCorrectiveAction());
793	                        newEntity.setOrgId(finding.getOrgId());
794	                        newEntity.setSecurityPatrolId(hseSecurityPatrolAnswer.getSecurityPatrolId());
795	                        newEntity.setTargetClosureDate(finding.getTargetClosureDate());
796	                        newEntity.setStatus(CorrectiveActionsEnum.OPEN.getCode());
797	                        hsePatrolCorrectiveActionService.save(newEntity);
798	
799	                        if (newEntity.getCorrectiveActionsId() != null && CollectionUtils.isNotEmpty(finding.getAttachmentList())) {
800	                            processAttachment(newEntity.getCorrectiveActionsId(),
801	                                    finding.getAttachmentList(), AttachTypeEnum.CORRECTIVE_ACTION);
802	                        }
803	                        if (newEntity.getCorrectiveActionsId() != null) {
804	                            newIds.add(newEntity.getCorrectiveActionsId());
805	                        }
806	                    }
807	                }
808	            }
809	
810	            for (HsePatrolCorrectiveAction oldEntity : oldList) {
811	                if (!newIds.contains(oldEntity.getCorrectiveActionsId())) {
812	                    hsePatrolCorrectiveActionService.removeById(oldEntity.getId());
813	                }
814	            }
815	        }
816	
817	    }
