842	        LambdaQueryWrapper<HsePatrolCorrectiveAction> caQuery = new LambdaQueryWrapper<>();
843	        caQuery.eq(HsePatrolCorrectiveAction::getSecurityPatrolId, securityPatrolId);
844	        List<HsePatrolCorrectiveAction> correctiveList = hsePatrolCorrectiveActionService.list(caQuery);
845	
846	        Map<Integer, Integer> tabCountMap = new HashMap<>();
847	        Map<String, Integer> floorCountMap = new HashMap<>();
848	
849	        for (HsePatrolCorrectiveAction ca : correctiveList) {
850	            HseSecurityPatrolAnswer answer = answerById.get(ca.getPatrolAnswerId());
851	            if (answer == null) {
852	                continue;
853	            }
854	            HseSecurityPatrolFormCategory section = securityPatrolFormCategoryMap.get(answer.getFormCategoryId());
855	            if (section == null || section.getType() == null) {
856	                continue;
857	            }
858	            tabCountMap.merge(section.getType(), 1, Integer::sum);
859	            if (StringUtils.isNotBlank(answer.getFloorCode())) {
860	                String floorKey = section.getType() + ":" + answer.getFloorCode();
861	                floorCountMap.merge(floorKey, 1, Integer::sum);
862	            }
863	        }
864	
865	        List<PatrolTabSummaryBO> tabSummaries = new ArrayList<>();
866	        for (InspectionFormSetupTypeEnum tab : InspectionFormSetupTypeEnum.values()) {
867	            PatrolTabSummaryBO summary = new PatrolTabSummaryBO();
868	            summary.setType(tab.getCode());
869	            summary.setIssueCount(tabCountMap.getOrDefault(tab.getCode(), 0));
870	            tabSummaries.add(summary);
871	        }
872	        detailBO.setTabSummaries(tabSummaries);
873	
874	        List<PatrolFloorSummaryBO> floorSummaries = new ArrayList<>();
875	        Set<String> floorKeysSeen = new HashSet<>();
876	        for (HseSecurityPatrolAnswer answer : answerList) {
877	            if (StringUtils.isBlank(answer.getFloorCode())) {
878	                continue;
879	            }
880	            HseSecurityPatrolFormCategory section = securityPatrolFormCategoryMap.get(answer.getFormCategoryId());
881	            if (section == null || section.getType() == null) {
882	                continue;
883	            }
884	            if (!InspectionFormSetupTypeEnum.INSIDE_THE_BUILDING.getCode().equals(section.getType())
885	                    && !InspectionFormSetupTypeEnum.PARKING.getCode().equals(section.getType())) {
886	                continue;
887	            }
888	            String floorKey = section.getType() + ":" + answer.getFloorCode();
889	            if (!floorKeysSeen.add(floorKey)) {
890	                continue;
891	            }
892	            PatrolFloorSummaryBO floorSummary = new PatrolFloorSummaryBO();
893	            floorSummary.setType(section.getType());
894	            floorSummary.setFloorCode(answer.getFloorCode());
895	            floorSummary.setIssueCount(floorCountMap.getOrDefault(floorKey, 0));
896	            floorSummaries.add(floorSummary);
897	        }
898	        detailBO.setFloorSummaries(floorSummaries);
899	    }
