252	    private void validateFormCategorySavePayload(FormCategorySaveTypeBO saveBO) {
253	        boolean isArabic = "ar".equals(userService.getLoginUser().getPreferredLanguage());
254	        
255	        if (saveBO == null) {
256	            throw new BusinessException(CommonError.PARAM_ERROR.getCode(), 
257	                    isArabic ? "مطلوب نص الطلب." : "Request body is required.");
258	        }
259	        if (saveBO.getType() == null) {
260	            throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
261	                    isArabic ? "نوع نموذج التفتيش مفقود. يرجى إعادة فتح علامة تبويب النموذج والمحاولة مرة أخرى." 
262	                             : "Inspection form type is missing. Please reopen the form tab and try again.");
263	        }
264	        if (saveBO.getSections() == null || saveBO.getSections().isEmpty()) {
265	            throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
266	                    isArabic ? "يرجى إضافة قسم تفتيش واحد على الأقل قبل الحفظ." 
267	                             : "Please add at least one inspection section before saving.");
268	        }
269	        List<FormCategorySaveBO> sections = saveBO.getSections();
270	        for (int si = 0; si < sections.size(); si++) {
271	            FormCategorySaveBO section = sections.get(si);
272	            int sectionNo = si + 1;
273	            if (section == null) {
274	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
275	                        isArabic ? "القسم " + sectionNo + " فارغ. قم بإزالة الصف الفارغ أو املأه." 
276	                                 : "Section " + sectionNo + " is empty. Remove the blank row or fill it in.");
277	            }
278	            List<PatrolFormItemSaveBO> items = section.getItems();
279	            if (CollectionUtils.isEmpty(items)) {
280	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
281	                        isArabic ? "القسم " + sectionNo + " (" + abbreviateLabel(section) + "): يرجى إضافة عنصر تفتيش واحد على الأقل." 
282	                                 : "Section " + sectionNo + " (" + abbreviateLabel(section) + "): please add at least one inspection item.");
283	            }
284	            for (int ii = 0; ii < items.size(); ii++) {
285	                PatrolFormItemSaveBO item = items.get(ii);
286	                int itemNo = ii + 1;
287	                if (item == null) {
288	                    throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
289	                            isArabic ? "القسم " + sectionNo + "، العنصر " + itemNo + " فارغ. قم بإزالة الصف الفارغ أو املأه." 
290	                                     : "Section " + sectionNo + ", item " + itemNo + " is empty. Remove the blank row or fill it in.");
291	                }
292	                if (item.getOrgId() == null) {
293	                    throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
294	                            isArabic ? "القسم " + sectionNo + "، العنصر " + itemNo + ": يرجى اختيار قسم مسؤول." 
295	                                     : "Section " + sectionNo + ", item " + itemNo + ": please select a responsible department.");
296	                }
297	                if (item.getSort() == null) {
298	                    throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
299	                            isArabic ? "القسم " + sectionNo + "، العنصر " + itemNo + ": الترتيب مطلوب." 
300	                                     : "Section " + sectionNo + ", item " + itemNo + ": sort is required.");
301	                }
302	            }
303	        }
