337	    private void validateItemNames(List<PatrolFormItemSaveBO> items) {
338	        boolean isArabic = "ar".equals(userService.getLoginUser().getPreferredLanguage());
339	        
340	        if (CollectionUtils.isEmpty(items)) {
341	            return;
342	        }
343	        Set<String> names = new HashSet<>();
344	        Set<String> nameArs = new HashSet<>();
345	        for (PatrolFormItemSaveBO item : items) {
346	            String name = StringUtils.trimToEmpty(item.getName());
347	            if (StringUtils.isNotBlank(name) && !names.add(name)) {
348	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
349	                        isArabic ? "داخل قسم واحد، يشترك عنصران في نفس النص الإنجليزي \"" + name + "\". يرجى جعل كل عنصر فريداً." 
350	                                 : "Within one section, two items share the same English text \"" + name + "\". Please make each item unique.");
351	            }
352	            String nameAr = StringUtils.trimToEmpty(item.getNameAr());
353	            if (StringUtils.isNotEmpty(nameAr) && !nameArs.add(nameAr)) {
354	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
355	                        isArabic ? "داخل قسم واحد، يشترك عنصران في نفس النص العربي \"" + nameAr + "\". يرجى جعل كل عنصر فريداً." 
356	                                 : "Within one section, two items share the same Arabic text \"" + nameAr + "\". Please make each item unique.");
357	            }
358	        }
359	    }
