372	    private void forkCategoryReplaceTemplate(HseSecurityPatrolFormCategory oldCategory, FormCategorySaveBO newCategory, Integer type) {
373	        Long oldCategoryId = oldCategory.getCategoryId();
374	        LambdaQueryWrapper<HseSecurityPatrolChecklistItem> itemQw = new LambdaQueryWrapper<>();
375	        itemQw.eq(HseSecurityPatrolChecklistItem::getCategoryId, oldCategoryId);
376	        List<HseSecurityPatrolChecklistItem> oldItems = hseSecurityPatrolChecklistItemService.list(itemQw);
377	        if (CollectionUtils.isNotEmpty(oldItems)) {
378	            hseSecurityPatrolChecklistItemService.removeBatchByIds(
379	                    oldItems.stream().map(HseSecurityPatrolChecklistItem::getId).collect(Collectors.toList()));
380	        }
381	        this.removeById(oldCategory.getId());
382	
383	        HseSecurityPatrolFormCategory categoryEntity = new HseSecurityPatrolFormCategory();
384	        BeanUtil.copyProperties(newCategory, categoryEntity);
385	
386	        categoryEntity.setId(null);
387	        categoryEntity.setCategoryId(IdWorker.getId());
388	        categoryEntity.setType(type);
389	        this.save(categoryEntity);
390	        saveChecklistItems(newCategory.getItems(), categoryEntity.getCategoryId());
391	    }
